import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.preference.PreferenceManager

class BiometricLogin(private val context: Context) {
    private val biometricPrompt = BiometricPrompt(context, object : BiometricPrompt.AuthenticationCallback() {
        override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
            // Handle authentication error
        }

        override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
            // Save authenticated flag in SharedPreferences
            PreferenceManager.getDefaultSharedPreferences(context).edit().putBoolean("authenticated", true).apply()

            // Bypass login screen
            startActivity(Intent(context, MainActivity::class.java))
        }

        override fun onAuthenticationFailed() {
            // Fallback to password if biometric fails
            startActivity(Intent(context, LoginActivity::class.java))
        }
    })

    fun authenticate() {
        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Please authenticate")
            .setSubtitle("Fingerprint or Password")
            .setDescription("Use your fingerprint to authenticate")
            .setNegativeButtonText("Use password instead")
            .build()

        biometricPrompt.authenticate(promptInfo)
    }
}